INSERT INTO quest_template (id, name, summary, offer_text, completion_text, level, required_level, zone_ref_id, giver_npc_id, turn_in_npc_id, reward_xp, reward_money) VALUES
  (8, 'Pelts for Bren', 'Gather 3 Coarse Wolf Pelts and bring them to Marshal Bren.', 'Good work on the culling. Now bring me three of their pelts — the Wardens need winter linings, and you''ve earned first pick of the stores.', 'These will keep a scout warm through the pass. Take your reward.', 7, 4, NULL, 7, NULL, 320, 150),
  (9, 'Thin the Pack', 'Slay 5 Gray Wolves on the north road for Marshal Bren.', 'The wolves have taken three wagons this month. Cull five of them and the rest will think twice before creeping down from the ridge.', 'Five fewer fangs on the road. You''ve a steady hand.', 6, 4, NULL, 7, NULL, 250, 300);
